from openai import OpenAI
import numpy as np

client = OpenAI()

def embed(text):
    response = client.embeddings.create(
        model="text-embedding-3-small",
        input=text
    )
    return np.array(response.data[0].embedding)

def cosine_similarity(a, b):
    return np.dot(a, b) / (np.linalg.norm(a) * np.linalg.norm(b))

v1 = embed("How do I reset my password?")
v2 = embed("I forgot my login credentials")
v3 = embed("What is the weather in Paris?")

print(cosine_similarity(v1, v2))  # → 0.91 (very similar)
print(cosine_similarity(v1, v3))  # → 0.31 (unrelated)

from openai import OpenAI
import json
client = OpenAI()

# Define tools as JSON schemas
tools = [{
    "type": "function",
    "function": {
        "name": "get_weather",
        "description": "Get current weather for a city",
        "parameters": {
            "type": "object",
            "properties": {
                "city": {"type": "string", "description": "City name"},
                "unit": {"type": "string", "enum": ["celsius", "fahrenheit"]}
            },
            "required": ["city"]
        }
    }
}]

# Actual tool implementation
def get_weather(city: str, unit: str = "celsius") -> dict:
    # In reality, call a weather API
    return {"city": city, "temperature": 22, "unit": unit, "condition": "Sunny"}

messages = [{"role": "user", "content": "What's the weather in Paris?"}]

# First LLM call — may request a tool
response = client.chat.completions.create(model="gpt-4o", messages=messages, tools=tools)

# Handle tool call
if response.choices[0].finish_reason == "tool_calls":
    tool_call = response.choices[0].message.tool_calls[0]
    args = json.loads(tool_call.function.arguments)
    result = get_weather(**args)

    # Add tool result to messages and call again
    messages.append(response.choices[0].message)  # Assistant message with tool_call
    messages.append({"role": "tool", "tool_call_id": tool_call.id, "content": json.dumps(result)})

    final = client.chat.completions.create(model="gpt-4o", messages=messages)
    print(final.choices[0].message.content)

import json
from openai import OpenAI
client = OpenAI()

def extract_user_facts(conversation: list[dict]) -> dict:
    """Use LLM to extract persistent facts from conversation."""
    response = client.chat.completions.create(
        model="gpt-4o-mini",
        messages=[
            {"role": "system", "content": "Extract user facts as JSON. Keys: name, preferences, goals."},
            {"role": "user", "content": f"Conversation:\n{json.dumps(conversation)}"}
        ],
        temperature=0,
        response_format={"type": "json_object"}
    )
    return json.loads(response.choices[0].message.content)

# After a conversation, extract and store facts
facts = extract_user_facts([
    {"role": "user", "content": "I'm Alice, I love Python and prefer concise answers"},
    {"role": "assistant", "content": "Got it, Alice! I'll be concise."}
])
# → {"name": "Alice", "preferences": ["Python", "concise answers"], "goals": []}

from openai import OpenAI
import json
client = OpenAI()

def evaluate_response(question: str, answer: str, reference: str) -> dict:
    """Use GPT-4o to score an answer against a reference."""

    judge_prompt = f"""You are an expert evaluator. Score the ANSWER against the REFERENCE.

    Question: {question}
    Reference answer: {reference}
    Model's answer: {answer}

    Score on these criteria (1-5 each):
    - accuracy: Is the answer factually correct?
    - completeness: Does it cover all key points?
    - conciseness: Is it appropriately brief?

    Respond as JSON: {{"accuracy": N, "completeness": N, "conciseness": N, "reasoning": "..."}}"""

    response = client.chat.completions.create(
        model="gpt-4o",  # Use strongest model as judge
        messages=[{"role": "user", "content": judge_prompt}],
        temperature=0,
        response_format={"type": "json_object"}
    )
    return json.loads(response.choices[0].message.content)

scores = evaluate_response(
    question="What is backpropagation?",
    answer="It's how neural networks learn by adjusting weights.",
    reference="Backpropagation is an algorithm that computes gradients of the loss function with respect to weights using the chain rule, enabling gradient descent optimization."
)
print(scores)  # {"accuracy": 4, "completeness": 2, "conciseness": 5, "reasoning": "..."}

from openai import OpenAI
import base64
client = OpenAI()

# Option 1: Pass a public image URL
response = client.chat.completions.create(
    model="gpt-4o",
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "What's in this image? List the main objects."},
            {"type": "image_url", "image_url": {"url": "https://example.com/image.jpg"}}
        ]
    }]
)
print(response.choices[0].message.content)

# Option 2: Base64 encode a local image
with open("local_image.jpg", "rb") as f:
    image_data = base64.b64encode(f.read()).decode("utf-8")

response = client.chat.completions.create(
    model="gpt-4o",
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "Extract all text visible in this screenshot."},
            {"type": "image_url", "image_url": {"url": f"data:image/jpeg;base64,{image_data}"}}
        ]
    }],
    max_tokens=1000
)
